1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const BLOCK_SIZE = 3;
21	const BLOCK_PRICE = 60;
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function basePremiumFor(item: ItemSpec): number {
34	  return BASE_PREMIUMS[item.type] ?? 0;
35	}
36	
37	function sumBasePremiums(items: ItemSpec[]): number {
38	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
39	}
40	
41	function countItemsOfType(items: ItemSpec[], type: string): number {
42	  return items.filter((item) => item.type === type).length;
43	}
44	
45	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
46	  const count = countItemsOfType(items, componentType);
47	  if (count !== BLOCK_SIZE) return 0;
48	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
49	}
50	
51	function blockAdjustment(items: ItemSpec[]): number {
52	  return COMPONENT_TYPES.reduce(
53	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
54	    0
55	  );
56	}
57	
58	export function quote(input: QuoteInput): QuoteResult {
59	  const policyBasePremium =
60	    sumBasePremiums(input.items) + blockAdjustment(input.items);
61	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
62	  return {
63	    premium: Math.ceil(policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE),
64	  };
65	}
66	
67	export function claim(): unknown {
68	  return undefined;
69	}
